typedef pair<ll, ll> P;

template<class T> inline bool chmax(T& a, T b) { if (a < b) { a = b; return true; } return false; }

template<class T> inline bool chmin(T& a, T b) { if (a > b) { a = b; return true; } return false; }



const int MOD=1e9+7;

const ll INF=1e18;

const int MAX=510000;

const double pi=acos(-1);

int dx[8] = {1,0,-1,0,1,1,-1,-1};

int dy[8] = {0,1,0,-1,-1,1,1,-1};

// Binary Indexed Tree (Fenwick Tree)

// https://youtu.be/lyHk98daDJo?t=7960

template<typename T>

struct BIT {

  int n;

  vector<T> d;

  BIT(int n=0):n(n),d(n+1) {}

  void add(int i, T x=1) {

    for (i++; i <= n; i += i&-i) {

      d[i] += x;

    }

  }

  T sum(int i) {

    T x = 0;

    for (i++; i; i -= i&-i) {

      x += d[i];

    }

    return x;

  }

  T sum(int l, int r) {

    return sum(r-1) - sum(l-1);

  }

};



int main(){

  cin.tie(0);

  ios::sync_with_stdio(false); 



  int n, q;

  cin >> n >> q;

  vector<int> a(n);

  rep(i,n) cin >> a[i];

  vector<int> pi(n+1,-1);//最後に出てきた場所

  vector<vector<int>> ps(n);

  rep(i,n){

    int l = pi[a[i]];

    if(l != -1) ps[l].emplace_back(i);

    pi[a[i]] = i;

  }



  vector<vector<P>>qs(n);

  rep(i,q){

    int l, r;

    cin >> l >> r;

    --l;

    --r;

    qs[l].emplace_back(r,i);

  }



  vector<int> ans(q);

  BIT<int> d(n);

  for(int x=n-1; x>=0; --x){

    for(int y:ps[x]) d.add(y,1);

    for(P query:qs[x]){

      int r = query.first, i = query.second;

      ans[i] = (r-x+1)-d.sum(r);

    }

  }



  rep(i,q) cout << ans[i] << endl;

  return 0;

}

