    expandL(expandL),expandR(expandR),shrinkL(shrinkL),shrinkR(shrinkR){}

  Mo(int n,int wid,F expand,F shrink){

    *this = Mo(n,wid,expand,expand,shrink,shrink);

  }

  // add queries [l, r)

  inline void add(int a,int b){

    l.emplace_back(a);

    r.emplace_back(b);

  }

