    uint64_t rank(int pos, int bit){

        int bpos = pos/b, lpos = pos/l, spos = pos/s;

        int nbit = b-pos%b -1;

        uint64_t mask = MASK - ((1LLU<<nbit)-1 + (1LLU<<nbit));

        uint64_t n = L[lpos] + S[spos] + pop_count(B[bpos] & mask);

