class SuccinctBitVector {

private:

    uint64_t size;                // ビットベクトルのサイズ

    uint32_t blockBitNum = 64;

    std::vector<uint64_t> B;            // ビットベクトル



    uint32_t LEVEL_L = 65536;

    uint32_t LEVEL_S = 256;

    std::vector<uint64_t> L;            // 大ブロック

    std::vector<uint16_t> S;            // 小ブロック



    uint64_t numOne = 0;                // 1bitの数



public:

    SuccinctBitVector(uint64_t n) : size(n) {

        const uint64_t s = (n + blockBitNum - 1) / blockBitNum + 1;   // ceil(n, blockSize)

        this->B.assign(s, 0);

        this->L.assign(n / LEVEL_L + 1, 0);

        this->S.assign(n / LEVEL_S + 1, 0);

    }



    // B[pos] = bit

    void setBit(uint64_t bit, uint64_t pos) {

        assert(bit == 0 or bit == 1);

        assert(pos < this->size);



        const uint64_t blockPos = pos / blockBitNum;

        const uint64_t offset = pos % blockBitNum;

        if (bit == 1) { B.at(blockPos) |= (1LLU << offset); }

        else          { B.at(blockPos) &= (~(1LLU << offset)); }

    }



    // B[pos]

    uint64_t access(uint64_t pos) const {

        assert(pos < this->size);

        const uint64_t blockPos = pos / blockBitNum;

        const uint64_t offset   = pos % blockBitNum;

        return ((B.at(blockPos) >> offset) & 1);

    }



    uint64_t operator[](uint64_t pos) const {

        return access(pos);

    }



    void build() {

        uint64_t num = 0;

        for (uint64_t i = 0; i <= size; i++){

            if (i % LEVEL_L == 0) {

                L.at(i / LEVEL_L) = num;

            }

            if (i % LEVEL_S == 0) {

                S.at(i / LEVEL_S) = num - L.at(i / LEVEL_L);

            }

            if (i != size and i % blockBitNum == 0) {

                num += this->popCount(this->B.at(i / blockBitNum));

            }

        }

        this-> numOne = num;

    }



    // B[0, pos)のbitの数

    uint64_t rank(uint64_t bit, uint64_t pos) const {

        assert(bit == 0 or bit == 1);

        assert(pos <= this->size);



        if (bit) { return rank1(pos); }

        else     { return pos - rank1(pos); }

    }



    // B[l, r)のbitの数

    uint64_t rank(uint64_t bit, uint64_t l, uint64_t r) const {

        return rank(bit, r) - rank(bit, l);

    }



    // rank番目のbitの位置 + 1(rankは1-origin)

    uint64_t select(const uint64_t bit, const uint64_t rank) const {

        assert(bit == 0 or bit == 1);

        assert(rank > 0);

        if (bit == 0 and rank > this->size - this-> numOne) { return NOTFOUND; }

        if (bit == 1 and rank > this-> numOne)              { return NOTFOUND; }



        // 大ブロックL内を検索

        uint64_t large_idx = 0;

        {

            uint64_t left = 0;

            uint64_t right = L.size();

            while (right - left > 1) {

                uint64_t mid = (left + right) / 2;

                uint64_t r = L.at(mid);

                r = (bit) ? r : mid * LEVEL_L - L.at(mid);



                if (r < rank) {

                    left = mid;

                    large_idx = mid;

                } else {

                    right = mid;

                }

            }

        }



        // 小ブロックS内を検索

        uint64_t small_idx = (large_idx * LEVEL_L) / LEVEL_S;

        {

            uint64_t left = (large_idx * LEVEL_L) / LEVEL_S;

            uint64_t right = std::min(((large_idx  + 1) * LEVEL_L) / LEVEL_S, S.size());

            while (right - left > 1) {

                uint64_t mid = (left + right) / 2;

                uint64_t r = L.at(large_idx) + S.at(mid);

                r = (bit) ? r :mid * LEVEL_S - r;



                if (r < rank) {

                    left = mid;

                    small_idx = mid;

                } else {

                    right = mid;

                }

            }

        }



        // Bをブロック単位で順番に探索

        uint64_t rank_pos = 0;

        {

            const uint64_t begin_block_idx = (small_idx * LEVEL_S) / blockBitNum;

            uint64_t total_bit = L.at(large_idx) + S.at(small_idx);

            if (bit == 0) {

                total_bit = small_idx * LEVEL_S - total_bit;

            }

            for (uint64_t i = 0;; ++i) {

                uint64_t b = popCount(B.at(begin_block_idx + i));

                if (bit == 0) {

                    b = blockBitNum - b;

                }

                if (total_bit + b >= rank) {

                    uint64_t block = (bit) ? B.at(begin_block_idx + i) : ~B.at(begin_block_idx + i);

                    rank_pos = (begin_block_idx + i) * blockBitNum + selectInBlock(block, rank - total_bit);

                    break;

                }

                total_bit += b;

            }

        }



        return rank_pos + 1;

    }



    uint64_t getNumOne() const {

        return numOne;

    }



    void debug() const {

        std::cout << "LEVEL_L(" << L.size() << ")" << std::endl;

        for (uint64_t i = 0 ; i < L.size(); ++i) {

            std::cout << L.at(i) << ", ";

        }

        std::cout << std::endl;

        std::cout << "LEVEL_S(" << S.size() << ")" << std::endl;

        for (uint64_t i = 0 ; i < S.size(); ++i) {

            std::cout << S.at(i) << ", ";

        }

        std::cout << std::endl;

    }



private:

    uint64_t rank1(uint64_t pos) const {

        uint64_t rank = L.at(pos / LEVEL_L) + S.at(pos / LEVEL_S);



        const uint64_t begin = (pos / LEVEL_S) * LEVEL_S / blockBitNum;

        const uint64_t end = pos / blockBitNum;

        for (uint64_t i = begin; i < end; ++i) {

            rank += popCount(this->B.at(i));

        }

        const uint64_t remain = (pos % LEVEL_S) % blockBitNum;

        rank += popCount(this->B.at(end) & ((1LLU << remain) - 1));



        return rank;

    }



    uint64_t popCount(uint64_t x) const {

        return __builtin_popcountll(x);

    }



    uint64_t selectInBlock(uint64_t x, uint64_t rank) const {

        uint64_t x1 = x - ((x & 0xAAAAAAAAAAAAAAAALLU) >> 1);

        uint64_t x2 = (x1 & 0x3333333333333333LLU) + ((x1 >> 2) & 0x3333333333333333LLU);

        uint64_t x3 = (x2 + (x2 >> 4)) & 0x0F0F0F0F0F0F0F0FLLU;



        uint64_t pos = 0;

        for (;;  pos += 8){

            uint64_t rank_next = (x3 >> pos) & 0xFFLLU;

            if (rank <= rank_next) break;

            rank -= rank_next;

        }



        uint64_t v2 = (x2 >> pos) & 0xFLLU;

        if (rank > v2) {

            rank -= v2;

            pos += 4;

        }



        uint64_t v1 = (x1 >> pos) & 0x3LLU;

        if (rank > v1){

            rank -= v1;

            pos += 2;

        }



        uint64_t v0  = (x >> pos) & 0x1LLU;

        if (v0 < rank){

            rank -= v0;

            pos += 1;

        }



        return pos;

    }

};



using namespace std;



struct BitVector {

    static constexpr int block_size = sizeof(uint64_t) * CHAR_BIT;  // blockのサイズ

    int n;

    std::vector<uint64_t> bit;

    std::vector<int> acc;

    BitVector() {}

    BitVector(int n_) : n(n_), bit(n / block_size + 1), acc(n / block_size + 1) {



    }

    void setBit(uint64_t b, uint64_t pos) {

        if (b) {

            bit[pos / block_size] |= (uint64_t)1 << (pos % block_size);

        }

        else {

            bit[pos / block_size] &= ~((uint64_t)1 << (pos % block_size));

        }

    }



    uint64_t access(uint64_t pos) const {

        return 0;

    }



    void build() {

        for (int i = 0; i < (int)acc.size() - 1; i++) {

            acc[i + 1] = acc[i] + __builtin_popcountll(bit[i]);

        }

    }



    uint64_t rank(uint64_t b, uint64_t pos) const {

        if (b) {

            return acc[pos / block_size] + (pos % block_size ? __builtin_popcountll(bit[pos / block_size] << (block_size - pos % block_size)) : 0);

        }

        else {

            return pos - rank(1, pos);

        }

    }



    uint64_t select(uint64_t b, uint64_t pos) const {

        return 0;

    }

};



class WaveletMatrix {

private:

    std::vector<BitVector> bit_arrays;

    std::vector<uint64_t> begin_one;                    // 各bitに着目したときの1の開始位置

    std::map<uint64_t, uint64_t> begin_alphabet;        // 最後のソートされた配列で各文字の開始位置

    std::vector<std::vector<uint64_t>> cumulative_sum;  // 各bitに着目したときの累積和



    uint64_t size;                                 // 与えられた配列のサイズ

    uint64_t maximum_element;                      // 文字数

    uint64_t bit_size;                             // 文字を表すのに必要なbit数



public:

    WaveletMatrix() {}



    WaveletMatrix(const std::vector<uint64_t> &array) {

        build(array);

    }



    void build(std::vector<uint64_t> array) {

        assert(!array.empty());

        this->size = array.size();

        this->maximum_element = *max_element(array.begin(), array.end()) + 1;

        this->bit_size = get_num_of_bit(this->maximum_element);

        if (this->bit_size == 0) {

            this->bit_size = 1;

        }



        this->bit_arrays.resize(this->bit_size, BitVector(this->size));

        this->begin_one.resize(this->bit_size);

//        this->cumulative_sum.resize(this->bit_size + 1, std::vector<uint64_t>(size + 1, 0));



//        for (uint64_t j = 0; j < array.size(); ++j) {

//            this->cumulative_sum.at(0).at(j + 1) = this->cumulative_sum.at(0).at(j) + array[j];

//        }



        for (uint64_t depth = 0; depth < this->bit_size; ++depth) {

            std::vector<uint64_t> zero, one;

            for (uint64_t i = 0; i < this->size; ++i) {

                const uint64_t bit = (array[i] >> (this->bit_size - depth - 1u)) & 1u;

                if (bit) {

                    one.push_back(array[i]);

                    this->bit_arrays[depth].setBit(1, i);

                } else {

                    zero.push_back(array[i]);

                }

            }

            this->bit_arrays[depth].build();

            this->begin_one[depth] = zero.size();



            array = std::move(zero);

            array.insert(array.end(), one.begin(), one.end());



//            for (uint64_t j = 0; j < array.size(); ++j) {

//                this->cumulative_sum.at(depth + 1).at(j + 1) = this->cumulative_sum.at(depth + 1).at(j) + array.at(j);

//            }

        }



        // ソートされた配列内での各文字の位置を取得

        for (int i = array.size() - 1; i >= 0; --i) {

            this->begin_alphabet[array.at(i)] = i;

        }

    }



    // v[pos]

    uint64_t access(uint64_t pos) const {

        if (pos >= this->size) { return NOTFOUND; }



        uint64_t c = 0;

        for (uint64_t i = 0; i < bit_arrays.size(); ++i) {

            uint64_t bit = bit_arrays.at(i).access(pos);   // もとの数値のi番目のbit

            c = (c <<= 1u) | bit;

            pos = bit_arrays.at(i).rank(bit, pos);

            if (bit) {

                pos += this->begin_one.at(i);

            }

        }

        return c;

    }



    // i番目のcの位置 + 1を返す。rankは1-origin

    uint64_t select(uint64_t c, uint64_t rank) const {

        assert(rank > 0);

        if (c >= maximum_element) {

            return NOTFOUND;

        }

        if (this->begin_alphabet.find(c) == this->begin_alphabet.end()) {

            return NOTFOUND;

        }



        uint64_t index = this->begin_alphabet.at(c) + rank;

        for (uint64_t i = 0; i < bit_arrays.size(); ++i) {

            uint64_t bit = ((c >> i) & 1);      // 下からi番目のbit

            if (bit == 1) {

                index -= this->begin_one.at(bit_size - i - 1);

            }

            index = this->bit_arrays.at(bit_size - i - 1).select(bit, index);

        }

        return index;

    }



    // v[begin_pos, end_pos)で最大値を返す

    uint64_t maxRange(uint64_t begin_pos, uint64_t end_pos) const {

        return quantileRange(begin_pos, end_pos, end_pos - begin_pos - 1);

    }



    // v[begin_pos, end_pos)で最小値を返す

    uint64_t minRange(uint64_t begin_pos, uint64_t end_pos) const {

        return quantileRange(begin_pos, end_pos, 0);

    }



    // v[begin_pos, end_pos)でk番目に小さい値を返す(kは0-origin)

    // つまり小さい順に並べてk番目の値

    uint64_t quantileRange(uint64_t begin_pos, uint64_t end_pos, uint64_t k) const {

        if ((end_pos > this->size || begin_pos >= end_pos) || (k >= end_pos - begin_pos)) {

            return NOTFOUND;

        }



        uint64_t val = 0;

        for (uint64_t depth = 0; depth < this->bit_size; ++depth) {

            const uint64_t num_of_zero_begin = this->bit_arrays.at(depth).rank(0, begin_pos);

            const uint64_t num_of_zero_end = this->bit_arrays.at(depth).rank(0, end_pos);

            const uint64_t num_of_zero = num_of_zero_end - num_of_zero_begin;     // beginからendまでにある0の数

            const uint64_t bit = (k < num_of_zero) ? 0 : 1;                       // k番目の値の上からi番目のbitが0か1か



            if (bit) {

                k -= num_of_zero;

                begin_pos = this->begin_one.at(depth) + begin_pos - num_of_zero_begin;

                end_pos = this->begin_one.at(depth) + end_pos - num_of_zero_end;

            } else {

                begin_pos = num_of_zero_begin;

                end_pos = num_of_zero_begin + num_of_zero;

            }



            val = ((val << 1u) | bit);

        }



        return val;

    }



    // v[begin_pos, end_pos)でk番目に小さい数値のindexを返す(kは0-origin)

    // つまり小さい順に並べてk番目の値のindex

    uint64_t quantileRange_index(uint64_t begin_pos, uint64_t end_pos, uint64_t k) const {

        if ((end_pos > this->size || begin_pos >= end_pos) || (k >= end_pos - begin_pos)) {

            return NOTFOUND;

        }



        uint64_t val = 0;

        for (uint64_t depth = 0; depth < this->bit_size; ++depth) {

            const uint64_t num_of_zero_begin = this->bit_arrays.at(depth).rank(0, begin_pos);

            const uint64_t num_of_zero_end = this->bit_arrays.at(depth).rank(0, end_pos);

            const uint64_t num_of_zero = num_of_zero_end - num_of_zero_begin;     // beginからendまでにある0の数

            const uint64_t bit = (k < num_of_zero) ? 0 : 1;                       // k番目の値の上からi番目のbitが0か1か



            if (bit) {

                k -= num_of_zero;

                begin_pos = this->begin_one.at(depth) + begin_pos - num_of_zero_begin;

                end_pos = this->begin_one.at(depth) + end_pos - num_of_zero_end;

            } else {

                begin_pos = num_of_zero_begin;

                end_pos = num_of_zero_begin + num_of_zero;

            }



            val = ((val << 1u) | bit);

        }



        uint64_t left = 0;

        for (uint64_t i = 0; i < this->bit_size; ++i) {

            const uint64_t bit = (val >> (this->bit_size - i - 1)) & 1u;  // 上からi番目のbit

            left = this->bit_arrays.at(i).rank(bit, left);               // cのi番目のbitと同じ数値の数

            if (bit) {

                left += this->begin_one.at(i);

            }

        }



        const uint64_t rank = begin_pos + k - left + 1;

        return select(val, rank) - 1;

    }



    // v[0, pos)のcの数

    uint64_t rank(uint64_t c, uint64_t pos) const {

        assert(pos < size);

        if (c >= maximum_element) {

            return 0;

        }

        if (this->begin_alphabet.find(c) == this->begin_alphabet.end()) {

            return 0;

        }



        for (uint64_t i = 0; i < bit_size; ++i) {

            uint64_t bit = (c >> (bit_size - i - 1)) & 1;  // 上からi番目のbit

            pos = bit_arrays.at(i).rank(bit, pos);         // cのi番目のbitと同じ数値の数

            if (bit) {

                pos += this->begin_one.at(i);

            }

        }



        uint64_t begin_pos = this->begin_alphabet.at(c);

        return pos - begin_pos;

    }



    // v[begin_pos, end_pos)で[min, max)に入る値の個数

    uint64_t rangeFreq(uint64_t begin_pos, uint64_t end_pos, uint64_t min_c, uint64_t max_c) const {

        if ((end_pos > size || begin_pos >= end_pos) || (min_c >= max_c) || min_c >= maximum_element) {

            return 0;

        }



        const auto maxi_t = rankAll(max_c, begin_pos, end_pos);

        const auto mini_t = rankAll(min_c, begin_pos, end_pos);

        return std::get<1>(maxi_t) - std::get<1>(mini_t);

    }



    // v[0, pos)でcより小さい文字の数

    uint64_t rankLessThan(uint64_t c, uint64_t begin, uint64_t end) const {

        auto t = rankAll(c, begin, end);

        return std::get<1>(t);

    }



    // v[0, pos)でcより大きい文字の数

    uint64_t rankMoreThan(uint64_t c, uint64_t begin, uint64_t end) const {

        auto t = rankAll(c, begin, end);

        return std::get<2>(t);

    }



    // v[begin, end)で(cと同じ値の数、cより小さい値の数、cより大きい値の数)を求める

    std::tuple<uint64_t, uint64_t, uint64_t> rankAll(const uint64_t c, uint64_t begin, uint64_t end) const {

        assert(end <= this->size);

        const uint64_t num = end - begin;



        if (begin >= end) {

            return std::make_tuple(0, 0, 0);

        }

        if (c >= this->maximum_element || end == 0) {

            return std::make_tuple(0, num, 0);

        }



        uint64_t rank_less_than = 0, rank_more_than = 0;

        for (size_t depth = 0; (depth < this->bit_size) and (begin < end); ++depth) {

            const uint64_t bit = (c >> (this->bit_size - depth - 1)) & 1u;



            const uint64_t rank0_begin = this->bit_arrays.at(depth).rank(0, begin);

            const uint64_t rank0_end = this->bit_arrays.at(depth).rank(0, end);

            const uint64_t rank1_begin = begin - rank0_begin;

            const uint64_t rank1_end = end - rank0_end;



            if (bit) {

                rank_less_than += (rank0_end - rank0_begin);    // depth番目のbitが0のものは除外される

                begin = this->begin_one.at(depth) + rank1_begin;

                end = this->begin_one.at(depth) + rank1_end;

            } else {

                rank_more_than += (rank1_end - rank1_begin);    // depth番目のbitが1のものは除外される

                begin = rank0_begin;

                end = rank0_end;

            }

        }



        const uint64_t rank = num - rank_less_than - rank_more_than;

        return std::make_tuple(rank, rank_less_than, rank_more_than);

